#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::vector<int> arr(5);
    for (int i = 0; i < 5; ++i) {
        std::cin >> arr[i];
    }

    if (arr.empty()) {
        std::cout << "Array is empty." << std::endl;
        return 1;
    }

    int largest = arr[0];
    for (int i = 1; i < 5; ++i) {
        if (arr[i] > largest) {
            largest = arr[i];
        }
    }
    std::cout << largest << std::endl;
    return 0;
}
